-- Seed brands and device models from exported CSV
-- Generated automatically on 2026-03-12
BEGIN;

ON CONFLICT (id) DO UPDATE
SET slug = EXCLUDED.slug,
    name = EXCLUDED.name;
ON CONFLICT (id) DO UPDATE
SET slug = EXCLUDED.slug,
    brand_id = EXCLUDED.brand_id,
    name = EXCLUDED.name,
    image_url = EXCLUDED.image_url,
    mockup_url = EXCLUDED.mockup_url;

COMMIT;


